/// <summary>
///
/// </summary>
public void clicked()
{
    Args                            args;
    Object                          formRun;

    ETG_LedgerExchangeAdjustmentTmp eTG_LedgerExchangeAdjustmentTmp;
    ETG_LedgerExchangeAdjustTmp     eTG_LedgerExchangeAdjustTmp;

    super();

    delete_from eTG_LedgerExchangeAdjustTmp;

    while select eTG_LedgerExchangeAdjustmentTmp
        where eTG_LedgerExchangeAdjustmentTmp.FromDate == FromDate.dateValue() &&
              eTG_LedgerExchangeAdjustmentTmp.ToDate ==   ToDate.dateValue()   &&
              eTG_LedgerExchangeAdjustmentTmp.ExchangeRateDate == ExchRateDate.dateValue()
    {
        eTG_LedgerExchangeAdjustTmp.FromDate                           = eTG_LedgerExchangeAdjustmentTmp.FromDate;
        eTG_LedgerExchangeAdjustTmp.ToDate                             = eTG_LedgerExchangeAdjustmentTmp.ToDate;
        eTG_LedgerExchangeAdjustTmp.ExchangeRateDate                   = eTG_LedgerExchangeAdjustmentTmp.ExchangeRateDate;
        eTG_LedgerExchangeAdjustTmp.AccountingCurrencyAmount           = eTG_LedgerExchangeAdjustmentTmp.AccountingCurrencyAmount;
        eTG_LedgerExchangeAdjustTmp.IsBalanceSheet                     = eTG_LedgerExchangeAdjustmentTmp.IsBalanceSheet;
        eTG_LedgerExchangeAdjustTmp.LedgerDimension                    = eTG_LedgerExchangeAdjustmentTmp.LedgerDimension;
        eTG_LedgerExchangeAdjustTmp.PostingLayer                       = eTG_LedgerExchangeAdjustmentTmp.PostingLayer;
        eTG_LedgerExchangeAdjustTmp.ReportingCurrencyAmount            = eTG_LedgerExchangeAdjustmentTmp.ReportingCurrencyAmount;
        eTG_LedgerExchangeAdjustTmp.TransactionCurrencyAmount          = eTG_LedgerExchangeAdjustmentTmp.TransactionCurrencyAmount;
        eTG_LedgerExchangeAdjustTmp.TransactionCurrencyCode            = eTG_LedgerExchangeAdjustmentTmp.TransactionCurrencyCode;
        eTG_LedgerExchangeAdjustTmp.ExchangeRateType                   = eTG_LedgerExchangeAdjustmentTmp.ExchangeRateType;
        eTG_LedgerExchangeAdjustTmp.MainAccount                        = eTG_LedgerExchangeAdjustmentTmp.MainAccount;
        eTG_LedgerExchangeAdjustTmp.AccountingCurrencyAdjustmentAmount = eTG_LedgerExchangeAdjustmentTmp.AccountingCurrencyAdjustmentAmount;
        eTG_LedgerExchangeAdjustTmp.ReportingCurrencyAdjustmentAmount  = eTG_LedgerExchangeAdjustmentTmp.ReportingCurrencyAdjustmentAmount;
        eTG_LedgerExchangeAdjustTmp.AccountingCurrencyCrossRate        = eTG_LedgerExchangeAdjustmentTmp.AccountingCurrencyCrossRate;
        eTG_LedgerExchangeAdjustTmp.ReportingCurrencyCrossRate         = eTG_LedgerExchangeAdjustmentTmp.ReportingCurrencyCrossRate;
        eTG_LedgerExchangeAdjustTmp.LegalEntity                        = eTG_LedgerExchangeAdjustmentTmp.LegalEntity;
        eTG_LedgerExchangeAdjustTmp.ReportingCurrencyExchangeRateType  = eTG_LedgerExchangeAdjustmentTmp.ReportingCurrencyExchangeRateType;
        eTG_LedgerExchangeAdjustTmp.Name                               = eTG_LedgerExchangeAdjustmentTmp.Name;
        eTG_LedgerExchangeAdjustTmp.ETGAccountExchangeType = eTG_LedgerExchangeAdjustmentTmp.ETGAccountExchangeType;
        eTG_LedgerExchangeAdjustTmp.ETGMainAccount = eTG_LedgerExchangeAdjustmentTmp.ETGMainAccount;
        eTG_LedgerExchangeAdjustTmp.ETGReportExchangeType = eTG_LedgerExchangeAdjustmentTmp.ETGReportExchangeType;
        eTG_LedgerExchangeAdjustTmp.NewAccountCurrencyAmt = eTG_LedgerExchangeAdjustmentTmp.NewAccountingCurrencyAmt;
        eTG_LedgerExchangeAdjustTmp.NewReportingCurrencyAmt = eTG_LedgerExchangeAdjustmentTmp.NewReportingCurrencyAmt;

        eTG_LedgerExchangeAdjustTmp.insert();
    }

    args = new Args();
    //args.record(ETG_Chargecodelines);
    args.name(formstr(ETG_LedgerExchAdjustment));
    formRun = classfactory.formRunClass(args);
    formRun.init();
    formRun.run();
    formRun.wait();

}
